                <Button variant="secondary" onClick={() => addEvent('crash')}>Add Crash</Button>
                <Button variant="secondary" onClick={() => addEvent('drift_up')}>Add Drift Up</Button>
                 <Button variant="secondary" onClick={() => addEvent('drift_down')}>Add Drift Down</Button>
